#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline class_T bench_value(class_T x, class_T f) {
  class_T t0 = x;
  class_T t1 = x;
  class_T t2 = x;
  class_T t3 = x;
  class_T t4 = x;
  class_T t5 = x;
  class_T t6 = x;
  class_T t7 = x;

  for (int j = 0; j < (COMPUTE_ITERATIONS / 8); ++j) {
    t0 = t0 * t0 + f;
    t1 = t1 * t1 + f;
    t2 = t2 * t2 + f;
    t3 = t3 * t3 + f;
    t4 = t4 * t4 + f;
    t5 = t5 * t5 + f;
    t6 = t6 * t6 + f;
    t7 = t7 * t7 + f;
  }

#if (COMPUTE_ITERATIONS % 8) > 0
  t0 = t0 * t0 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
  t1 = t1 * t1 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
  t2 = t2 * t2 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
  t3 = t3 * t3 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
  t4 = t4 * t4 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
  t5 = t5 * t5 + f;
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
  t6 = t6 * t6 + f;
#endif

  return t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
}

__kernel void benchmark_func(const class_T seed, __global class_T* data) {
  (void)seed;

  const size_t gid = get_global_id(0);
  const size_t lid = get_local_id(0);
  const size_t gsize = get_global_size(0);
  const size_t group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const size_t base = group * ((size_t)blockdim * ELEMENTS_PER_THREAD * FUSION_DEGREE) + lid;
  const size_t stride = (size_t)blockdim;
#else
  const size_t base = gid;
  const size_t stride = gsize;
#endif

  for (size_t fusion = 0; fusion < (size_t)FUSION_DEGREE; ++fusion) {
    const size_t chunk_base = base + fusion * (size_t)ELEMENTS_PER_THREAD * stride;
    const class_T f = data[chunk_base];

    for (size_t e = 0; e < (size_t)ELEMENTS_PER_THREAD; ++e) {
      const size_t idx = chunk_base + e * stride;
      const class_T x = data[idx];
      data[idx] = bench_value(x, f);
    }
  }
}
